<template><section class="page"><RouterLink :to="`/prompts/${promptId}/versions`">← {{t('promptops.version.history')}}</RouterLink><div v-if="loading" class="state">{{t('promptops.common.loading')}}</div><div v-else-if="!version" class="state">{{t('promptops.version.notFound')}}</div><template v-else><header><div><h2>{{version.name}} · {{version.versionNumber}}</h2><p>{{version.changeSummary}}</p></div><span>{{version.status}}</span></header><div class="summary"><article><small>Created By</small><strong>{{version.createdBy.name}}</strong></article><article><small>Created At</small><strong>{{version.createdAt}}</strong></article><article><small>Risk</small><strong>{{version.riskLevel}}</strong></article><article><small>Score</small><strong>{{version.evaluationScore??'—'}}</strong></article></div><article class="card"><h3>Change Reason</h3><p>{{version.changeReason||'—'}}</p></article><div class="grid"><article class="card"><h3>System Prompt</h3><pre>{{version.systemPrompt||'—'}}</pre></article><article class="card"><h3>User Prompt</h3><pre>{{version.userPrompt||'—'}}</pre></article></div><article class="card"><h3>{{t('promptops.editor.variables')}}</h3><div v-for="item in version.variables" :key="item.id"><code>&#123;&#123;{{item.name}}&#125;&#125;</code> · {{item.type}} · {{item.required?'required':'optional'}}</div></article><article class="card"><h3>{{t('promptops.editor.modelConfig')}}</h3><p>{{version.modelProvider}} / {{version.modelName}} · Temperature {{version.temperature}} · Max Tokens {{version.maxTokens}}</p><p>{{t('promptops.editor.outputType')}}: {{version.outputType}} · {{version.expectedOutputFormat||'—'}}</p></article></template></section></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import{RouterLink,useRoute}from'vue-router';import{useI18n}from'vue-i18n';import type{PromptOpsPromptVersion as PromptVersion}from'@prompt-optimizer/core';import{usePromptOpsServices}from'../../services/promptops';const{t}=useI18n(),route=useRoute(),services=usePromptOpsServices(),promptId=String(route.params.id);const version=ref<PromptVersion>(),loading=ref(true);onMounted(async()=>{const value=await services.promptVersionRepository.getById(String(route.params.versionId));version.value=value?.promptId===promptId?value:undefined;loading.value=false})</script>
<style scoped>.page{display:grid;gap:16px}.page>a{color:#2563eb;text-decoration:none}header{display:flex;justify-content:space-between}header h2{margin:0}.summary{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}.summary article,.card{padding:16px;border:1px solid #e5e7eb;border-radius:10px;background:var(--n-color,#fff)}.summary small,.summary strong{display:block}.summary small{color:#64748b;margin-bottom:7px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:14px}.card pre{white-space:pre-wrap;font:inherit}.state{text-align:center;padding:55px}@media(max-width:800px){.summary,.grid{grid-template-columns:1fr}}</style>
